from pydantic import BaseModel, EmailStr, validator, ValidationError, root_validator
from typing import Optional
import json

class Address(BaseModel):
    street: str
    city: str
    state: str
    zip_code: str

    @validator('street')
    def street_must_not_be_blank(cls, v):
        if not v.strip():
            raise ValueError('Street address must not be empty')
        return v

    @validator('city')
    def city_must_not_be_blank(cls, v):
        if not v.strip():
            raise ValueError('City must not be empty')
        return v

    @validator('state')
    def state_must_be_two_letters(cls, v):
        if not v.isalpha() or len(v) != 2:
            raise ValueError('State must be a two-letter abbreviation (e.g., "CA")')
        return v.upper()

    @validator('zip_code')
    def zip_code_format(cls, v):
        import re
        if not re.fullmatch(r'\d{5}(-\d{4})?', v):
            raise ValueError('Zip code must be in "12345" or "12345-6789" format')
        return v

class UserProfile(BaseModel):
    name: str
    email: EmailStr
    age: int
    address: Address

    @validator('name')
    def name_must_be_alpha(cls, v):
        if not v.strip():
            raise ValueError('Name must not be empty')
        if not all(part.isalpha() for part in v.split()):
            raise ValueError('Name must contain only alphabetic characters and spaces')
        return v.title()

    @validator('age')
    def age_must_be_reasonable(cls, v):
        if v < 0:
            raise ValueError('Age cannot be negative')
        if v > 150:
            raise ValueError('Age is unrealistically high')
        return v

    def to_json(self, *, indent: Optional[int] = None) -> str:
        # Use pydantic's json method which returns a JSON string
        return self.json(indent=indent)

    @classmethod
    def from_json(cls, json_str: str) -> 'UserProfile':
        return cls.parse_raw(json_str)
